1	/**
2	 * ShapePointSelector.tsx
3	 *
4	 * Reusable left-list + right-slot point assignment panel for shape placement
5	 * and configuration wizards. Mirrors ChartPointSelector's interaction model:
6	 *   - Left: searchable infinite-scroll point list (tagname + display_name)
7	 *   - Right: one drop zone per active bindable part
8	 *   - Drag to slot · Double-click adds to first empty slot · Right-click context menu
9	 *
10	 * Default-point logic: the "body" slot is the primary binding. When body has
11	 * a point and another slot is empty, that slot shows "Using default: <tagname>"
12	 * and inherits the body's point at config-build time.
13	 */
14	
15	import React, { useState, useEffect, useCallback, useRef } from "react";
16	import { useInfiniteQuery } from "@tanstack/react-query";
17	import { pointsApi } from "../../../api/points";
18	import type { PointMeta } from "../../../api/points";
19	import {
20	  extractPoints,
21	  isIOClipboardPayload,
22	  useIOClipboardStore,
23	  buildIOClipboardPayload,
24	} from "../../../shared/clipboard";
25	import type { IOClipboardPayload } from "../../../shared/clipboard";
26	import ContextMenu from "../../../shared/components/ContextMenu";
27	import type { ContextMenuItem } from "../../../shared/components/ContextMenu";
28	
29	// ---------------------------------------------------------------------------
30	// Types (exported so callers can type their state)
31	// ---------------------------------------------------------------------------
32	
33	export interface ShapeSlotDef {
34	  partId: string;
35	  label: string;
36	  /** True for the "body" (primary / default) part. */
37	  isDefault: boolean;
38	}
39	
40	export interface ShapeBindingEntry {
41	  partKey: string;
42	  tag: string;
43	  pointId: string;
44	  displayName?: string;
45	  /** Engineering unit from point metadata (e.g. "%" or "°C") */
46	  unit?: string;
47	  /** EU range low from point metadata */
48	  rangeLo?: number;
49	  /** EU range high from point metadata */
50	  rangeHi?: number;
51	}
52	
53	export interface AdditionalPointEntry {
54	  pointId: string;
55	  tag: string;
56	  displayName?: string;
57	  unit?: string;
58	}
59	
60	interface ShapePointSelectorProps {
61	  slots: ShapeSlotDef[];
62	  bindings: ShapeBindingEntry[];
63	  onChange: (bindings: ShapeBindingEntry[]) => void;
64	  /** Called whenever over-capacity state changes. Parent uses this to block Apply/Place. */
65	  onOverCapacityChange?: (isOverCapacity: boolean) => void;
66	  /** When provided, renders an extra point-list section below the regular slots. */
67	  additionalPoints?: AdditionalPointEntry[];
68	  onAdditionalPointsChange?: (pts: AdditionalPointEntry[]) => void;
69	  /** Section header label for the additional points group (e.g. "Text Readout Array"). */
70	  additionalPointsLabel?: string;
71	}
72	
73	// ---------------------------------------------------------------------------
74	// ShapePointSelector
75	// ---------------------------------------------------------------------------
76	
77	export function ShapePointSelector({
78	  slots,
79	  bindings,
80	  onChange,
81	  onOverCapacityChange,
82	  additionalPoints,
83	  onAdditionalPointsChange,
84	  additionalPointsLabel,
85	}: ShapePointSelectorProps) {
86	  const [search, setSearch] = useState("");
87	  const [debouncedSearch, setDebouncedSearch] = useState("");
88	  const [dragPointId, setDragPointId] = useState<string | null>(null);
89	  const [dragOverSlot, setDragOverSlot] = useState<string | null>(null);
90	  const [dragOverAdditionalIdx, setDragOverAdditionalIdx] = useState<
91	    number | null
92	  >(null);
93	  const [ctxMenu, setCtxMenu] = useState<{
94	    x: number;
95	    y: number;
96	    pt?: PointMeta;
97	  } | null>(null);
98	  const sentinelRef = useRef<HTMLDivElement>(null);
99	
100	  const { current: currentPayload, previous: previousPayload } =
101	    useIOClipboardStore();
102	
103	  useEffect(() => {
104	    const t = setTimeout(() => setDebouncedSearch(search), 250);
105	    return () => clearTimeout(t);
106	  }, [search]);
107	
108	  const PAGE_SIZE = 100;
109	  const {
110	    data: infiniteData,
111	    isFetching,
112	    fetchNextPage,
113	    hasNextPage,
114	  } = useInfiniteQuery({
115	    queryKey: ["shape-point-search", debouncedSearch],
116	    queryFn: ({ pageParam }) =>
117	      pointsApi.list({
118	        search: debouncedSearch || undefined,
119	        limit: PAGE_SIZE,
120	        page: pageParam as number,
121	      }),
122	    initialPageParam: 1,
123	    getNextPageParam: (lastPage) => {
124	      if (!lastPage.success) return undefined;
125	      const { page, pages } = lastPage.data.pagination;
126	      return page < pages ? page + 1 : undefined;
127	    },
128	    staleTime: 30_000,
129	  });
130	
131	  const allPoints: PointMeta[] = infiniteData
132	    ? infiniteData.pages.flatMap((p) => (p.success ? p.data.data : []))
133	    : [];
134	
135	  const onSentinelVisible = useCallback(
136	    (entries: IntersectionObserverEntry[]) => {
137	      if (entries[0]?.isIntersecting && hasNextPage && !isFetching) {
138	        fetchNextPage();
139	      }
140	    },
141	    [fetchNextPage, hasNextPage, isFetching],
142	  );
143	
144	  useEffect(() => {
145	    const el = sentinelRef.current;
146	    if (!el) return;
147	    const observer = new IntersectionObserver(onSentinelVisible, {
148	      threshold: 0.1,
149	    });
150	    observer.observe(el);
151	    return () => observer.disconnect();
152	  }, [onSentinelVisible]);
153	
154	  const defaultBinding = bindings.find((b) => b.partKey === "body");
155	
156	  const isOverCapacity = slots.some(
157	    (slot) =>
158	      bindings.filter((b) => b.partKey === slot.partId && b.pointId).length > 1,
159	  );
160	
161	  useEffect(() => {
162	    onOverCapacityChange?.(isOverCapacity);
163	  }, [isOverCapacity, onOverCapacityChange]);
164	
165	  function assignPoint(partId: string, pt: PointMeta) {
166	    // Only update the first matching entry so over-cap extras are preserved
167	    let done = false;
168	    onChange(
169	      bindings.map((b) => {
170	        if (b.partKey === partId && !done) {
171	          done = true;
172	          return {
173	            ...b,
174	            tag: pt.tagname,
175	            pointId: pt.id,
176	            displayName: pt.display_name ?? undefined,
177	            unit: pt.unit ?? undefined,
178	            rangeLo: pt.eu_range_low ?? undefined,
179	            rangeHi: pt.eu_range_high ?? undefined,
180	          };
181	        }
182	        return b;
183	      }),
184	    );
185	  }
186	
187	  function clearPoint(partId: string, pointId: string) {
188	    const totalForPart = bindings.filter((b) => b.partKey === partId).length;
189	    if (totalForPart <= 1) {
190	      // Keep the placeholder entry but blank it
191	      onChange(
192	        bindings.map((b) =>
193	          b.partKey === partId && b.pointId === pointId
194	            ? {
195	                ...b,
196	                tag: "",
197	                pointId: "",
198	                displayName: undefined,
199	                unit: undefined,
200	                rangeLo: undefined,
201	                rangeHi: undefined,
202	              }
203	            : b,
204	        ),
205	      );
206	    } else {
207	      // Remove this specific over-cap entry
208	      const idx = bindings.findIndex(
209	        (b) => b.partKey === partId && b.pointId === pointId,
210	      );
211	      if (idx >= 0)
212	        onChange([...bindings.slice(0, idx), ...bindings.slice(idx + 1)]);
213	    }
214	  }
215	
216	  function handleDrop(partId: string) {
217	    if (!dragPointId) return;
218	    const pt = allPoints.find((p) => p.id === dragPointId);
219	    if (pt) assignPoint(partId, pt);
220	    setDragPointId(null);
221	    setDragOverSlot(null);
222	  }
223	
224	  function handleDoubleClick(pt: PointMeta) {
225	    const target = slots.find((s) => {
226	      const b = bindings.find((b) => b.partKey === s.partId);
227	      return !b?.pointId;
228	    });
229	    if (target) {
230	      assignPoint(target.partId, pt);
231	    } else if (onAdditionalPointsChange && additionalPoints !== undefined) {
232	      onAdditionalPointsChange([
233	        ...additionalPoints,
234	        {
235	          pointId: pt.id,
236	          tag: pt.tagname,
237	          displayName: pt.display_name ?? undefined,
238	          unit: pt.unit ?? undefined,
239	        },
240	      ]);
241	    }
242	  }
243	
244	  async function resolvePointMeta(tagname: string): Promise<PointMeta | null> {
245	    const found = allPoints.find((p) => p.tagname === tagname);
246	    if (found) return found;
247	    try {
248	      const res = await pointsApi.list({ search: tagname, limit: 5 });
249	      if (!res.success) return null;
250	      return res.data.data.find((p) => p.tagname === tagname) ?? null;
251	    } catch {
252	      return null;
253	    }
254	  }
255	
256	  async function handlePasteFromClipboard(payload: IOClipboardPayload) {
257	    const refs = extractPoints(payload);
258	    if (refs.length === 0) return;
259	
260	    const resolved: PointMeta[] = [];
261	    for (const ref of refs) {
262	      const pt = await resolvePointMeta(ref.tagname);
263	      if (pt) resolved.push(pt);
264	    }
265	    if (resolved.length === 0) return;
266	
267	    let updatedBindings = [...bindings];
268	    let refIdx = 0;
269	
270	    // Pass 1: fill each slot's primary (first empty) binding in order
271	    for (const slot of slots) {
272	      if (refIdx >= resolved.length) break;
273	      const idx = updatedBindings.findIndex(
274	        (b) => b.partKey === slot.partId && !b.pointId,
275	      );
276	      if (idx >= 0) {
277	        const pt = resolved[refIdx++];
278	        updatedBindings[idx] = {
279	          ...updatedBindings[idx],
280	          tag: pt.tagname,
281	          pointId: pt.id,
282	          displayName: pt.display_name ?? undefined,
283	          unit: pt.unit ?? undefined,
284	          rangeLo: pt.eu_range_low ?? undefined,
285	          rangeHi: pt.eu_range_high ?? undefined,
286	        };
287	      }
288	    }
289	
290	    // Pass 2: remaining refs go into the first slot as over-cap entries —
291	    // they appear in the UI so the user can remove the excess before placing.
292	    const firstPartId = slots[0]?.partId;
293	    if (firstPartId) {
294	      while (refIdx < resolved.length) {
295	        const pt = resolved[refIdx++];
296	        updatedBindings.push({
297	          partKey: firstPartId,
298	          tag: pt.tagname,
299	          pointId: pt.id,
300	          displayName: pt.display_name ?? undefined,
301	          unit: pt.unit ?? undefined,
302	          rangeLo: pt.eu_range_low ?? undefined,
303	          rangeHi: pt.eu_range_high ?? undefined,
304	        });
305	      }
306	    }
307	
308	    onChange(updatedBindings);
309	  }
310	
311	  function handleContainerPaste(e: React.ClipboardEvent) {
312	    const text = e.clipboardData.getData("text/plain");
313	    try {
314	      const parsed: unknown = JSON.parse(text);
315	      if (isIOClipboardPayload(parsed)) {
316	        e.preventDefault();
317	        handlePasteFromClipboard(parsed);
318	      }
319	    } catch {
320	      // not IO clipboard data
321	    }
322	  }
323	
324	  function handleContextMenu(e: React.MouseEvent, pt: PointMeta) {
325	    e.preventDefault();
326	    e.stopPropagation();
327	    setCtxMenu({ x: e.clientX, y: e.clientY, pt });
328	  }
329	
330	  function handleContainerContextMenu(e: React.MouseEvent) {
331	    if ((e.target as HTMLElement).closest("[data-point-item]")) return;
332	    e.preventDefault();
333	    setCtxMenu({ x: e.clientX, y: e.clientY });
334	  }
335	
336	  function buildPasteItems(
337	    payload: IOClipboardPayload | null,
338	    pasteLabel: string,
339	  ): ContextMenuItem[] {
340	    if (!payload || extractPoints(payload).length === 0)
341	      return [{ label: pasteLabel, disabled: true }];
342	
343	    const pasteAsChildren: ContextMenuItem[] = slots.map((slot) => ({
344	      label: slot.label,
345	      onClick: async () => {
346	        const refs = extractPoints(payload);
347	        if (!refs.length) return;
348	        const pt = await resolvePointMeta(refs[0].tagname);
349	        if (pt) assignPoint(slot.partId, pt);
350	      },
351	    }));
352	
353	    return [
354	      { label: pasteLabel, onClick: () => handlePasteFromClipboard(payload) },
355	      { label: `${pasteLabel} As…`, children: pasteAsChildren },
356	    ];
357	  }
358	
359	  const assignedPointIds = new Set(
360	    bindings.filter((b) => b.pointId).map((b) => b.pointId),
361	  );
362	
363	  const inputStyle: React.CSSProperties = {
364	    width: "100%",
365	    height: 26,
366	    background: "var(--io-input-bg)",
367	    border: "1px solid var(--io-input-border)",
368	    color: "var(--io-text-primary)",
369	    fontSize: "1em",
370	    padding: "0 8px",
371	    borderRadius: 4,
372	    outline: "none",
373	    boxSizing: "border-box",
374	    flexShrink: 0,
375	  };
376	
377	  return (
378	    <>
379	      <div
380	        tabIndex={-1}
381	        onPaste={handleContainerPaste}
382	        onContextMenu={handleContainerContextMenu}
383	        style={{
384	          display: "grid",
385	          gridTemplateColumns: "40% 1fr",
386	          gridTemplateRows: "auto auto 1fr auto",
387	          columnGap: 12,
388	          rowGap: 6,
389	          flex: 1,
390	          minHeight: 0,
391	          outline: "none",
392	        }}
393	      >
394	        {/* ── Left col label ─────────────────────────────────────────────────── */}
395	        <div
396	          style={{
397	            gridColumn: 1,
398	            gridRow: 1,
399	            fontSize: "0.85em",
400	            fontWeight: 600,
401	            color: "var(--io-text-muted)",
402	            textTransform: "uppercase",
403	            letterSpacing: "0.05em",
404	          }}
405	        >
406	          Available Points
407	        </div>
408	
409	        {/* ── Left col search ────────────────────────────────────────────────── */}
410	        <input
411	          type="text"
412	          placeholder="Search…"
413	          value={search}
414	          onChange={(e) => setSearch(e.target.value)}
415	          style={{ ...inputStyle, gridColumn: 1, gridRow: 2 }}
416	        />
417	
418	        {/* ── Left col list ──────────────────────────────────────────────────── */}
419	        <div
420	          onDragStart={(e) => e.stopPropagation()}
421	          style={{
422	            gridColumn: 1,
423	            gridRow: 3,
424	            overflowY: "auto",
425	            border: "1px solid var(--io-border)",
426	            borderRadius: 4,
427	            background: "var(--io-surface)",
428	            minHeight: 0,
429	          }}
430	        >
431	          {allPoints.length === 0 && (
432	            <div
433	              style={{
434	                padding: 12,
435	                color: "var(--io-text-muted)",
436	                fontSize: 12,
437	              }}
438	            >
439	              {isFetching ? "Searching…" : search ? "No matches" : "Loading…"}
440	            </div>
441	          )}
442	          {allPoints.map((pt) => {
443	            const isAssigned = assignedPointIds.has(pt.id);
444	            return (
445	              <div
446	                key={pt.id}
447	                data-point-item
448	                draggable
449	                onDragStart={() => setDragPointId(pt.id)}
450	                onDoubleClick={() => handleDoubleClick(pt)}
451	                onContextMenu={(e) => handleContextMenu(e, pt)}
452	                title={
453	                  pt.display_name
454	                    ? `${pt.tagname}\n${pt.display_name}`
455	                    : pt.tagname
456	                }
457	                style={{
458	                  padding: "4px 8px",
459	                  fontSize: "0.9em",
460	                  cursor: "grab",
461	                  borderBottom: "1px solid var(--io-border)",
462	                  color: "var(--io-text-primary)",
463	                  userSelect: "none",
464	                  borderLeft: isAssigned
465	                    ? "3px solid var(--io-accent)"
466	                    : "3px solid transparent",
467	                  background: isAssigned
468	                    ? "color-mix(in srgb, var(--io-accent) 8%, transparent)"
469	                    : undefined,
470	                }}
471	                onMouseEnter={(e) => {
472	                  e.currentTarget.style.background = isAssigned
473	                    ? "color-mix(in srgb, var(--io-accent) 16%, var(--io-surface-hover))"
474	                    : "var(--io-surface-hover)";
475	                }}
476	                onMouseLeave={(e) => {
477	                  e.currentTarget.style.background = isAssigned
478	                    ? "color-mix(in srgb, var(--io-accent) 8%, transparent)"
479	                    : "";
480	                }}
481	              >
482	                <div
483	                  style={{
484	                    fontWeight: 500,
485	                    overflow: "hidden",
486	                    textOverflow: "ellipsis",
487	                    whiteSpace: "nowrap",
488	                  }}
489	                >
490	                  {pt.tagname}
491	                </div>
492	                {pt.display_name && (
493	                  <div
494	                    style={{
495	                      color: "var(--io-text-muted)",
496	                      fontSize: "0.8em",
497	                      overflow: "hidden",
498	                      textOverflow: "ellipsis",
499	                      whiteSpace: "nowrap",
500	                    }}
501	                  >
502	                    {pt.display_name}
503	                  </div>
504	                )}
505	              </div>
506	            );
507	          })}
508	          <div ref={sentinelRef} style={{ height: 1, flexShrink: 0 }} />
509	          {isFetching && allPoints.length > 0 && (
510	            <div
511	              style={{
512	                padding: "6px 8px",
513	                fontSize: 11,
514	                color: "var(--io-text-muted)",
515	                textAlign: "center",
516	              }}
517	            >
518	              Loading…
519	            </div>
520	          )}
521	        </div>
522	
523	        {/* ── Left col hint ──────────────────────────────────────────────────── */}
524	        <div
525	          style={{
526	            gridColumn: 1,
527	            gridRow: 4,
528	            fontSize: "0.75em",
529	            color: "var(--io-text-muted)",
530	          }}
531	        >
532	          Drag to slot · Double-click to add · Right-click for options · Ctrl+V
533	          to paste
534	        </div>
535	
536	        {/* ── Right col header ───────────────────────────────────────────────── */}
537	        <div
538	          style={{
539	            gridColumn: 2,
540	            gridRow: 1,
541	            fontSize: "0.85em",
542	            fontWeight: 600,
543	            color: "var(--io-text-muted)",
544	            textTransform: "uppercase",
545	            letterSpacing: "0.05em",
546	          }}
547	        >
548	          Point Assignments
549	        </div>
550	
551	        {/* ── Right col slots ────────────────────────────────────────────────── */}
552	        <div
553	          style={{
554	            gridColumn: 2,
555	            gridRow: "2 / 5",
556	            display: "flex",
557	            flexDirection: "column",
558	            gap: 12,
559	            minHeight: 0,
560	            overflowY: "auto",
561	          }}
562	        >
563	          {slots.map((slot) => {
564	            const slotBindings = bindings.filter(
565	              (b) => b.partKey === slot.partId && b.pointId,
566	            );
567	            const hasOwn = slotBindings.length > 0;
568	            const isOverCap = slotBindings.length > 1;
569	            const usesDefault =
570	              !slot.isDefault && !hasOwn && Boolean(defaultBinding?.pointId);
571	            const isEmpty = !hasOwn && !usesDefault;
572	            const isOver = dragOverSlot === slot.partId;
573	
574	            return (
575	              <div key={slot.partId}>
576	                {/* Slot label */}
577	                <div
578	                  style={{
579	                    fontSize: "0.78em",
580	                    fontWeight: 600,
581	                    textTransform: "uppercase",
582	                    letterSpacing: "0.05em",
583	                    marginBottom: 4,
584	                    display: "flex",
585	                    alignItems: "center",
586	                    gap: 6,
587	                    color: isOverCap
588	                      ? "var(--io-alarm-urgent)"
589	                      : slot.isDefault
590	                        ? "var(--io-accent)"
591	                        : "var(--io-text-muted)",
592	                  }}
593	                >
594	                  {slot.label}
595	                  {isOverCap ? (
596	                    <span
597	                      style={{
598	                        fontWeight: 400,
599	                        fontSize: "0.9em",
600	                        color: "var(--io-alarm-urgent)",
601	                        textTransform: "none",
602	                        letterSpacing: 0,
603	                      }}
604	                    >
605	                      — {slotBindings.length}/1 Too Many Points Selected
606	                    </span>
607	                  ) : slot.isDefault ? (
608	                    <span
609	                      style={{
610	                        fontWeight: 400,
611	                        fontSize: "0.9em",
612	                        color: "var(--io-text-muted)",
613	                        textTransform: "none",
614	                        letterSpacing: 0,
615	                      }}
616	                    >
617	                      — default
618	                    </span>
619	                  ) : null}
620	                </div>
621	
622	                {/* Drop zone */}
623	                <div
624	                  onDragOver={(e) => {
625	                    e.preventDefault();
626	                    setDragOverSlot(slot.partId);
627	                  }}
628	                  onDragLeave={() => setDragOverSlot(null)}
629	                  onDrop={() => handleDrop(slot.partId)}
630	                  style={{
631	                    border: `1px dashed ${
632	                      isOver
633	                        ? "var(--io-accent)"
634	                        : isEmpty
635	                          ? "color-mix(in srgb, var(--io-accent) 35%, var(--io-border))"
636	                          : "var(--io-border)"
637	                    }`,
638	                    borderRadius: 6,
639	                    padding: isEmpty ? "14px 12px" : "6px 8px",
640	                    background: isOver
641	                      ? "color-mix(in srgb, var(--io-accent) 8%, var(--io-surface))"
642	                      : isEmpty
643	                        ? "color-mix(in srgb, var(--io-accent) 4%, var(--io-surface))"
644	                        : "var(--io-surface)",
645	                    transition:
646	                      "border-color 0.15s, background 0.15s, padding 0.15s",
647	                    display: "flex",
648	                    flexDirection: "column",
649	                    gap: 4,
650	                  }}
651	                >
652	                  {/* Empty state */}
653	                  {isEmpty && (
654	                    <div
655	                      style={{
656	                        display: "flex",
657	                        flexDirection: "column",
658	                        alignItems: "center",
659	                        gap: 4,
660	                        color: isOver
661	                          ? "var(--io-accent)"
662	                          : "var(--io-text-muted)",
663	                        pointerEvents: "none",
664	                      }}
665	                    >
666	                      <svg
667	                        width="18"
668	                        height="18"
669	                        viewBox="0 0 22 22"
670	                        fill="none"
671	                        style={{ opacity: 0.5 }}
672	                      >
673	                        <rect
674	                          x="1"
675	                          y="5"
676	                          width="20"
677	                          height="14"
678	                          rx="2"
679	                          stroke="currentColor"
680	                          strokeWidth="1.5"
681	                          strokeDasharray="3 2"
682	                        />
683	                        <path
684	                          d="M11 9v6M8 12l3-3 3 3"
685	                          stroke="currentColor"
686	                          strokeWidth="1.5"
687	                          strokeLinecap="round"
688	                          strokeLinejoin="round"
689	                        />
690	                      </svg>
