295	export default function PointPickerModal({
296	  open,
297	  onClose,
298	  onSelect,
299	}: PointPickerModalProps) {
300	  const [search, setSearch] = useState("");
301	  const [debouncedQ, setDebouncedQ] = useState("");
302	  const [selected, setSelected] = useState<PointMeta | null>(null);
303	  const [tab, setTab] = useState<ViewTab>("search");
304	  const [favorites, setFavorites] = useState<PointMeta[]>(() =>
305	    loadJsonArray(FAVORITES_KEY),
306	  );
307	  const [recent] = useState<PointMeta[]>(() => loadJsonArray(RECENT_KEY));
308	  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
309	
310	  useEffect(() => {
311	    if (debounceRef.current) clearTimeout(debounceRef.current);
312	    debounceRef.current = setTimeout(() => setDebouncedQ(search), 250);
313	    return () => {
314	      if (debounceRef.current) clearTimeout(debounceRef.current);
315	    };
316	  }, [search]);
317	
318	  const pointsQuery = useQuery({
319	    queryKey: ["point-picker-search", debouncedQ],
320	    queryFn: () => pointsApi.list({ search: debouncedQ, limit: 50 }),
321	    enabled: debouncedQ.length >= 1,
322	    staleTime: 30_000,
323	  });
324	
325	  const allPointsQuery = useQuery({
326	    queryKey: ["point-picker-all"],
327	    queryFn: () => pointsApi.list({ limit: 200 }),
328	    staleTime: 60_000,
329	  });
330	
331	  const searchResults: PointMeta[] = useMemo(() => {
332	    if (!pointsQuery.data?.success) return [];
333	    const d = pointsQuery.data.data;
334	    return Array.isArray(d) ? d : ((d as { data?: PointMeta[] })?.data ?? []);
335	  }, [pointsQuery.data]);
336	
337	  const allPoints: PointMeta[] = useMemo(() => {
338	    if (!allPointsQuery.data?.success) return [];
339	    const d = allPointsQuery.data.data;
340	    return Array.isArray(d) ? d : ((d as { data?: PointMeta[] })?.data ?? []);
341	  }, [allPointsQuery.data]);
342	
343	  const tree = useMemo(() => buildTree(allPoints), [allPoints]);
344	
345	  const handleSelect = useCallback((p: PointMeta) => {
346	    setSelected(p);
347	  }, []);
348	
