350	    if (!selected) return;
351	    // Update recent
352	    const newRecent = [
353	      selected,
354	      ...recent.filter((r) => r.id !== selected.id),
355	    ].slice(0, 10);
356	    saveJsonArray(RECENT_KEY, newRecent);
357	    onSelect(selected.tagname, selected.id);
358	    onClose();
359	  }, [selected, recent, onSelect, onClose]);
360	
361	  const toggleFavorite = useCallback((p: PointMeta) => {
362	    setFavorites((prev) => {
363	      const exists = prev.some((f) => f.id === p.id);
364	      const next = exists ? prev.filter((f) => f.id !== p.id) : [...prev, p];
365	      saveJsonArray(FAVORITES_KEY, next);
366	      return next;
367	    });
368	  }, []);
369	
370	  const isFav = useCallback(
371	    (id: string) => favorites.some((f) => f.id === id),
372	    [favorites],
373	  );
374	
375	  // Keyboard handler
376	  useEffect(() => {
377	    if (!open) return;
378	    const handler = (e: KeyboardEvent) => {
379	      if (e.key === "Escape") onClose();
380	      if (e.key === "Enter" && selected) handleConfirm();
381	    };
382	    window.addEventListener("keydown", handler);
383	    return () => window.removeEventListener("keydown", handler);
384	  }, [open, onClose, selected, handleConfirm]);
385	
386	  if (!open) return null;
387	
388	  const renderList = (points: PointMeta[]) =>
389	    points.length === 0 ? (
390	      <div
