444	              {p.unit}
445	            </span>
446	          )}
447	        </div>
448	      ))
449	    );
450	
451	  return (
452	    <div style={overlayStyle} onClick={onClose}>
453	      <div style={dialogStyle} onClick={(e) => e.stopPropagation()}>
454	        {/* Header */}
