473	        <div style={{ padding: "8px 16px", position: "relative" }}>
474	          <SearchIcon />
475	          <input
476	            autoFocus
477	            type="text"
478	            placeholder="Search by tag, description, area..."
479	            value={search}
480	            onChange={(e) => {
481	              setSearch(e.target.value);
482	              setTab("search");
483	            }}
484	            style={searchStyle}
485	          />
486	        </div>
487	
