// ---------------------------------------------------------------------------
// Resizable palette section — header + scrollable content + bottom drag handle
// ---------------------------------------------------------------------------

interface PaletteSectionProps {
  title: string;
  open: boolean;
  onToggle: () => void;
  /** Controlled height of the scrollable content area in px. Omit for flexible. */
  height?: number;
  /** If true, fills remaining flex space instead of using a fixed height. */
  flexible?: boolean;
  onHeightChange?: (dy: number) => void;
  children: React.ReactNode;
}

function PaletteSection({
  title,
  open,
  onToggle,
  height,
  flexible = false,
  onHeightChange,
  children,
}: PaletteSectionProps) {
  const startY = useRef(0);
  const activeRef = useRef(false);
  const [isResizing, setIsResizing] = useState(false);

  const canResize = !flexible && !!onHeightChange;

  function handleResizeMouseDown(e: React.MouseEvent) {
    e.preventDefault();
    e.stopPropagation();
    activeRef.current = true;
    startY.current = e.clientY;
    setIsResizing(true);

    const onMove = (ev: MouseEvent) => {
      if (!activeRef.current) return;
      const dy = ev.clientY - startY.current;
      startY.current = ev.clientY;
      onHeightChange!(dy);
    };
    const onUp = () => {
      activeRef.current = false;
      setIsResizing(false);
      document.removeEventListener("mousemove", onMove);
      document.removeEventListener("mouseup", onUp);
    };
    document.addEventListener("mousemove", onMove);
    document.addEventListener("mouseup", onUp);
  }

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        flexShrink: 0,
        overflow: "hidden",
        ...(flexible && open ? { flex: "1 1 0", minHeight: 80 } : {}),
      }}
    >
      <SectionHeader label={title} open={open} onToggle={onToggle} />
      {open && (
        <>
          <div
            style={{
              overflowY: "auto",
              overflowX: "hidden",
              ...(flexible ? { flex: 1 } : { height: height ?? "auto" }),
            }}
          >
            {children}
          </div>
          {canResize && (
            <div
              draggable={false}
              onDragStart={(e) => e.preventDefault()}
              onMouseDown={handleResizeMouseDown}
              style={{
                height: 4,
                flexShrink: 0,
                cursor: "ns-resize",
                background: isResizing ? "var(--io-accent)" : "transparent",
                transition: "background 0.1s",
                borderBottom: "1px solid var(--io-border)",
                userSelect: "none",
              }}
              onMouseEnter={(e) => {
                if (!isResizing)
                  (e.currentTarget as HTMLElement).style.background =
                    "var(--io-surface-elevated)";
              }}
              onMouseLeave={(e) => {
                if (!isResizing)
                  (e.currentTarget as HTMLElement).style.background =
                    "transparent";
              }}
            />
          )}
        </>
      )}
    </div>
  );
}

