/**
 * DesignerRightPanel.tsx
 *
 * Context-sensitive property inspector panel.
 * Uses concern-based tabs (Layout / Style / Data / Shape / Content / Doc)
 * that appear conditionally based on the selected node type.
 */

import React, { useState, useCallback, useEffect, useRef } from "react";
import {
  useSceneStore,
  useHistoryStore,
  useLibraryStore,
  useUiStore,
} from "../../store/designer";
import type { NodeId } from "../../shared/types/graphics";
import type {
  SceneNode,
  SymbolInstance,
  TextBlock,
  Primitive,
  Pipe,
  DisplayElement,
  LayerDefinition,
  GraphicDocument,
  NavigationLink,
  WidgetNode,
  DisplayElementType,
  DisplayElementConfig,
  TextReadoutConfig,
  TextReadoutArrayConfig,
  AnalogBarConfig,
  FillGaugeConfig,
  SparklineConfig,
