                strokeWidth="1.2"
                fill="none"
                style={{ color: "var(--io-text-muted)" }}
              />
            </svg>
          </div>
        ))}
      </div>
    );
  }

  return (
    <div style={{ display: "flex", flexDirection: "column" }}>
      {/* Upload button row */}
      <div
        style={{
          padding: "6px 8px",
