          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.borderColor = "var(--io-accent)";
            e.currentTarget.style.color = "var(--io-accent)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.borderColor = "var(--io-border)";
            e.currentTarget.style.color = "var(--io-text-muted)";
