// ---------------------------------------------------------------------------
// Hook: execute + push to history
// ---------------------------------------------------------------------------

function useExecuteCmd() {
  const doc = useSceneStore((s) => s.doc);
  const execute = useSceneStore((s) => s.execute);
  const push = useHistoryStore((s) => s.push);

  return useCallback(
    (cmd: SceneCommand) => {
      if (!doc) return;
      const before = doc;
      execute(cmd);
      push(cmd, before);
    },
    [doc, execute, push],
  );
}

