// ---------------------------------------------------------------------------
// TransformSection — universal layout tab for all nodes
// ---------------------------------------------------------------------------

function TransformSection({
  node,
  doc,
  executeCmd,
  showRotation = true,
}: {
  node: SceneNode;
  doc: GraphicDocument | null;
  executeCmd: (cmd: SceneCommand) => void;
  showRotation?: boolean;
}) {
  const t = node.transform;
  const pos = t.position;
  const scale = t.scale ?? { x: 1, y: 1 };
  const mirror = t.mirror ?? "none";

  function setTransform(patch: Partial<Transform>) {
    executeCmd(
      new ChangePropertyCommand(node.id, "transform", { ...t, ...patch }, t),
    );
  }

  return (
    <>
      <div
        style={{
          display: "grid",
          gridTemplateColumns: "1fr 1fr",
          gap: 6,
          marginBottom: 6,
        }}
      >
        <Field label="X">
          <NumberInput
            value={Math.round(pos.x)}
            onChange={(v) => setTransform({ position: { ...pos, x: v } })}
          />
        </Field>
        <Field label="Y">
          <NumberInput
            value={Math.round(pos.y)}
            onChange={(v) => setTransform({ position: { ...pos, y: v } })}
          />
        </Field>
        {showRotation && (
          <Field label="Rotation °">
            <NumberInput
              value={Math.round(t.rotation)}
              min={-360}
              max={360}
              onChange={(v) => setTransform({ rotation: v })}
            />
          </Field>
        )}
        <Field label="Opacity %">
          <NumberInput
            value={Math.round(node.opacity * 100)}
            min={0}
            max={100}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "opacity",
                  v / 100,
                  node.opacity,
                ),
              )
            }
          />
        </Field>
        <Field label="Scale X %">
          <NumberInput
            value={Math.round(scale.x * 100)}
            min={1}
            max={2000}
            onChange={(v) => setTransform({ scale: { ...scale, x: v / 100 } })}
          />
        </Field>
        <Field label="Scale Y %">
          <NumberInput
            value={Math.round(scale.y * 100)}
            min={1}
            max={2000}
            onChange={(v) => setTransform({ scale: { ...scale, y: v / 100 } })}
          />
        </Field>
      </div>

      <Field label="Mirror">
        <SelectInput
          value={mirror}
          onChange={(v) => setTransform({ mirror: v as Transform["mirror"] })}
          options={[
            { value: "none", label: "None" },
            { value: "horizontal", label: "Horizontal" },
            { value: "vertical", label: "Vertical" },
            { value: "both", label: "Both" },
          ]}
        />
      </Field>

      <div style={{ display: "flex", gap: 12, marginBottom: 10 }}>
        <label
          style={{
            display: "flex",
            alignItems: "center",
            gap: 4,
            fontSize: 11,
            cursor: "pointer",
            color: "var(--io-text-secondary)",
          }}
        >
          <input
            type="checkbox"
            checked={node.visible}
            onChange={(e) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "visible",
                  e.target.checked,
                  node.visible,
                ),
              )
            }
            style={{ cursor: "pointer" }}
          />
          Visible
        </label>
        <label
          style={{
            display: "flex",
            alignItems: "center",
            gap: 4,
            fontSize: 11,
            cursor: "pointer",
            color: "var(--io-text-secondary)",
          }}
        >
          <input
            type="checkbox"
            checked={node.locked}
            onChange={(e) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "locked",
                  e.target.checked,
                  node.locked,
                ),
              )
            }
            style={{ cursor: "pointer" }}
          />
          Locked
        </label>
      </div>

      {doc && (
        <Field label="Layer">
          <SelectInput
            value={node.layerId ?? ""}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "layerId",
                  v || undefined,
                  node.layerId,
                ),
              )
            }
            options={[
              { value: "", label: "— None —" },
              ...doc.layers.map((l) => ({ value: l.id, label: l.name })),
            ]}
          />
        </Field>
      )}

      <NavigationLinkEditor
        nodeId={node.id}
        link={node.navigationLink}
        prevLink={node.navigationLink}
        executeCmd={executeCmd}
      />
    </>
  );
}

