function PrimitiveGeometrySection({
  node,
  executeCmd,
}: {
  node: Primitive;
  executeCmd: (cmd: SceneCommand) => void;
}) {
  const geo = node.geometry;
  if (geo.type === "rect") {
    return (
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
        <Field label="Width">
          <NumberInput
            value={geo.width}
            min={1}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "geometry",
                  { ...geo, width: v },
                  geo,
                ),
              )
            }
          />
        </Field>
        <Field label="Height">
          <NumberInput
            value={geo.height}
            min={1}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "geometry",
                  { ...geo, height: v },
                  geo,
                ),
              )
            }
          />
        </Field>
        <Field label="Corner Radius">
          <NumberInput
            value={geo.rx ?? 0}
            min={0}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "geometry",
                  { ...geo, rx: v, ry: v },
                  geo,
                ),
              )
            }
          />
        </Field>
      </div>
    );
  }
  if (geo.type === "circle") {
    return (
      <Field label="Radius">
        <NumberInput
          value={geo.r}
          min={1}
          onChange={(v) =>
            executeCmd(
              new ChangePropertyCommand(
                node.id,
                "geometry",
                { ...geo, r: v },
                geo,
              ),
            )
          }
        />
      </Field>
    );
  }
  if (geo.type === "ellipse") {
    return (
      <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 6 }}>
        <Field label="Radius X">
          <NumberInput
            value={geo.rx}
            min={1}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "geometry",
                  { ...geo, rx: v },
                  geo,
                ),
              )
            }
          />
        </Field>
        <Field label="Radius Y">
          <NumberInput
            value={geo.ry}
            min={1}
            onChange={(v) =>
              executeCmd(
                new ChangePropertyCommand(
                  node.id,
                  "geometry",
                  { ...geo, ry: v },
                  geo,
                ),
              )
            }
          />
        </Field>
      </div>
    );
  }
  return null;
}

