interface StencilItem {
  id: string;
  name: string;
}

function StencilTile({
  item,
  collapsed,
}: {
  item: StencilItem;
  collapsed: boolean;
}) {
  const [deleteOpen, setDeleteOpen] = useState(false);

  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      // Only handle left-click drags; right-clicks go to the context menu
      if (e.button !== 0) return;
      e.preventDefault();
      const ghost = document.createElement("div");
      ghost.id = "io-canvas-drag-ghost";
      ghost.setAttribute("data-drag-ghost", "true");
      ghost.style.cssText = [
        "position:fixed",
        "pointer-events:none",
        "z-index:9999",
        "opacity:0.7",
        "padding:4px 8px",
        "background:var(--io-accent)",
        "color:#09090b",
        "border-radius:4px",
        "font-size:11px",
        "font-weight:600",
        "transform:translate(-50%,-50%)",
        `left:${e.clientX}px`,
        `top:${e.clientY}px`,
        "display:block",
        "visibility:visible",
      ].join(";");
      ghost.textContent = item.name;
      document.body.appendChild(ghost);
      const onMove = (ev: MouseEvent) => {
        ghost.style.left = `${ev.clientX}px`;
        ghost.style.top = `${ev.clientY}px`;
      };
      const onUp = (ev: MouseEvent) => {
        ghost.remove();
        document.removeEventListener("mousemove", onMove, true);
        document.removeEventListener("mouseup", onUp, true);
        document.removeEventListener("keydown", onKeyDown, true);
        document.dispatchEvent(
          new CustomEvent("io:stencil-drop", {
            detail: { stencilId: item.id, x: ev.clientX, y: ev.clientY },
          }),
        );
      };
      const onKeyDown = (ev: KeyboardEvent) => {
        if (ev.key === "Escape") {
          ghost.remove();
          document.removeEventListener("mousemove", onMove, true);
          document.removeEventListener("mouseup", onUp, true);
          document.removeEventListener("keydown", onKeyDown, true);
        }
      };
      document.addEventListener("mousemove", onMove, true);
      document.addEventListener("mouseup", onUp, true);
      document.addEventListener("keydown", onKeyDown, true);
    },
    [item.id, item.name],
  );

  function handleExportSvg() {
    graphicsApi
      .exportShapeSvg(item.id)
      .then((svgContent) => {
        const blob = new Blob([svgContent], { type: "image/svg+xml" });
        const url = URL.createObjectURL(blob);
        const a = document.createElement("a");
        a.href = url;
        a.download = `${item.name}.svg`;
        a.click();
        URL.revokeObjectURL(url);
      })
      .catch((err) => {
        console.error("[StencilTile] SVG export failed:", err);
      });
  }

  function handleEdit() {
    // TODO: open stencil editor when implemented
    console.warn(
      "[StencilTile] Edit stencil: stencil editor not yet implemented for stencil",
      item.id,
    );
  }

  function handleDeleteConfirmed() {
    // TODO: call delete API when endpoint is available
    console.warn(
      "[StencilTile] Delete stencil: API not yet implemented for stencil",
      item.id,
    );
  }

  const { menuState, handleContextMenu, closeMenu } = useContextMenu();

  const stencilMenuItems = [
    { label: "Edit", onClick: handleEdit },
    { label: "Export SVG", onClick: handleExportSvg },
    {
      label: "Delete",
      onClick: () => setDeleteOpen(true),
      danger: true,
      divider: true,
    },
  ];

  if (collapsed) {
    return (
      <>
        <div
          onMouseDown={handleMouseDown}
          onContextMenu={handleContextMenu}
          title={item.name}
          style={{
            width: 28,
            height: 28,
            background: "var(--io-surface-elevated)",
            border: "1px solid var(--io-border)",
            borderRadius: "var(--io-radius)",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 9,
            color: "var(--io-text-muted)",
            cursor: "grab",
            userSelect: "none",
          }}
        >
          {item.name.slice(0, 2).toUpperCase()}
        </div>
        {menuState && (
          <ContextMenu
            x={menuState.x}
            y={menuState.y}
            items={stencilMenuItems}
            onClose={closeMenu}
          />
        )}
        <DeleteConfirmDialog
          open={deleteOpen}
          onOpenChange={setDeleteOpen}
          label={item.name}
          onConfirm={handleDeleteConfirmed}
        />
      </>
    );
  }

  return (
    <>
      <div
        onMouseDown={handleMouseDown}
        onContextMenu={handleContextMenu}
        title={item.name}
        style={{
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          gap: 3,
          width: 64,
