              }}
            >
              {v[0]!.toUpperCase() + v.slice(1)}
            </button>
          ))}
        </div>
      </Field>
      <Field label="Single Line">
        <input
          type="checkbox"
          checked={cfg.singleLine ?? false}
          onChange={(e) => patch({ singleLine: e.target.checked })}
          style={{ cursor: "pointer" }}
        />
      </Field>
      <Field label="Item Spacing">
        <NumberInput
